        /// <summary>
        /// <br/>
        /// cimtype: string<br/>
        /// <br/>
        /// </summary>
        public String Caption { get; set; }
        /// <summary>
        /// Boolean indicating that the physical media is used for cleaning purposes and not data storage.<br/>
        /// <br/>
        /// cimtype: boolean<br/>
        /// <br/>
        /// </summary>
        public Boolean CleanerMedia { get; set; }
        /// <summary>
        /// CreationClassName indicates the name of the class or the subclass used in the creation of an instance.<br/>
        /// When used with the other key properties of this class, this property allows all instances of this class and its subclasses to be uniquely identified.<br/>
        /// <br/>
        /// cimtype: string<br/>
        /// <br/>
        /// </summary>
        public String CreationClassName { get; set; }
        /// <summary>
        /// <br/>
        /// cimtype: string<br/>
        /// <br/>
        /// </summary>
        public String Description { get; set; }
        /// <summary>
        /// A physical component can be hot swapped if it is possible to replace the element with a physically different but equivalent one while the containing package has power applied to it (i.e., is &apos;on&apos;).<br/>
        /// For example, a fan component may be designed to be hot swapped.<br/>
        /// All components that can be hot swapped are inherently removable and replaceable .<br/>
        /// <br/>
        /// cimtype: boolean<br/>
        /// <br/>
        /// </summary>
        public Boolean HotSwappable { get; set; }
        /// <summary>
        /// <br/>
        /// cimtype: datetime<br/>
        /// <br/>
        /// </summary>
        public DateTime InstallDate { get; set; }
        /// <summary>
        /// The name of the organization responsible for producing the physical element.<br/>
        /// This may be the entity from whom the element is purchased, but this is not necessarily true.<br/>
        /// The latter information is contained in the Vendor property of CIM_Product.<br/>
        /// <br/>
        /// cimtype: string<br/>
        /// <br/>
        /// </summary>
        public String Manufacturer { get; set; }
        /// <summary>
        /// Additional detail related to the MediaType enumeration.<br/>
        /// For example, if value 3 (&quot;QIC Cartridge&quot;) is specified, this property could indicate whether the tape is wide or 1/4 inch, whether it is pre-formatted, whether it is Travan compatible, etc.<br/>
        /// <br/>
        /// cimtype: string<br/>
        /// <br/>
        /// </summary>
        public String MediaDescription { get; set; }
        /// <summary>
        /// Specifies the type of the physical media, as an enumerated integer.<br/>
        /// The MediaDescription property is used to provide more explicit definition of the media type, whether it is pre-formatted, compatibility features, etc.<br/>
        /// <br/>
        /// cimtype: uint16<br/>
        /// <br/>
        /// </summary>
        public UInt16 MediaType { get; set; }
        /// <summary>
        /// The name by which the physical element is generally known.<br/>
        /// <br/>
        /// cimtype: string<br/>
        /// <br/>
        /// </summary>
        public String Model { get; set; }
        /// <summary>
        /// <br/>
        /// cimtype: string<br/>
        /// <br/>
        /// </summary>
        public String Name { get; set; }
        /// <summary>
        /// OtherIdentifyingInfo captures additional data, beyond asset tag information, that could be used to identify a physical element.<br/>
        /// One example is bar code data associated with an element that also has an asset tag.<br/>
        /// Note that if only bar code data is available and is unique/able to be used as an element key, this property would be NULL and the bar code data used as the class key, in the tag property.<br/>
        /// <br/>
        /// cimtype: string<br/>
        /// <br/>
        /// </summary>
        public String OtherIdentifyingInfo { get; set; }
        /// <summary>
        /// The part number assigned by the organization responsible for producing or manufacturing the physical element.<br/>
        /// <br/>
        /// cimtype: string<br/>
        /// <br/>
        /// </summary>
        public String PartNumber { get; set; }
        /// <summary>
        /// Boolean indicating that the physical element is powered on (TRUE), or is currently off (FALSE).<br/>
        /// <br/>
        /// cimtype: boolean<br/>
        /// <br/>
        /// </summary>
        public Boolean PoweredOn { get; set; }
        /// <summary>
        /// A physical component is removable if it is designed to be taken in and out of the physical container in which it is normally found, without impairing the function of the overall packaging.<br/>
        /// A component can still be removable if power must be &apos;off&apos; in order to perform the removal.<br/>
        /// If power can be &apos;on&apos; and the component removed, then the element is removable and can be hot swapped.<br/>
        /// For example, an upgradeable processor chip is removable.<br/>
        /// <br/>
        /// cimtype: boolean<br/>
        /// <br/>
        /// </summary>
        public Boolean Removable { get; set; }
        /// <summary>
        /// A physical component is replaceable  if it is possible to replace (FRU or upgrade) the element with a physically different one.<br/>
        /// For example, some computer systems allow the main processor chip to be upgraded to one of a higher clock rating.<br/>
        /// In this case, the processor is said to be replaceable .<br/>
        /// All removable components are inherently replaceable .<br/>
        /// <br/>
        /// cimtype: boolean<br/>
        /// <br/>
        /// </summary>
        public Boolean Replaceable { get; set; }
        /// <summary>
        /// The Serial number property is a manufacturer-allocated number used to identify the physicalmedia.<br/>
        /// Example: WD-WM3493798728 for a disk serial number.<br/>
        /// <br/>
        /// cimtype: string<br/>
        /// <br/>
        /// override: SerialNumber<br/>
        /// <br/>
        /// </summary>
        public String SerialNumber { get; set; }
        /// <summary>
        /// The stock keeping unit number for this physical element.<br/>
        /// <br/>
        /// cimtype: string<br/>
        /// <br/>
        /// </summary>
        public String SKU { get; set; }
        /// <summary>
        /// <br/>
        /// cimtype: string<br/>
        /// <br/>
        /// </summary>
        public String Status { get; set; }
        /// <summary>
        /// The Tag property uniquely identifies the physical media in the system.<br/>
        /// Example: \\PHYSICALDRIVE0<br/>
        /// <br/>
        /// cimtype: string<br/>
        /// <br/>
        /// override: Tag<br/>
        /// <br/>
        /// </summary>
        public String Tag { get; set; }
        /// <summary>
        /// A string indicating the version of the physical element.<br/>
        /// <br/>
        /// cimtype: string<br/>
        /// <br/>
        /// </summary>
        public String Version { get; set; }
        /// <summary>
        /// Boolean specifying whether the media is currently write protected by some kind of physical mechanism, such as a protect tab on a floppy diskette.<br/>
        /// <br/>
        /// cimtype: boolean<br/>
        /// <br/>
        /// </summary>
        public Boolean WriteProtectOn { get; set; }
    }
    
