        /// <br/>
        /// cimtype: string<br/>
        /// <br/>
        /// </summary>
        public String[] HardwareID { get; set; }
        /// <summary>
        /// <br/>
        /// cimtype: datetime<br/>
        /// <br/>
        /// </summary>
