        /// </summary>
        public UInt32 FillAttribute { get; set; }
        /// <summary>
        /// The PriorityClass property controls the priority class of the new process (used to determine the scheduling priorities of the threads in the process).<br/>
        /// If the PriorityClass property is left null, the priority class defaults to Normal unless the priority class of the creating process is Idle or Below_Normal.<br/>
        /// In these cases, the child process receives the default priority class of the calling process.<br/>
        /// One of the following values can be specified:<br/>
        /// High - Indicates a process that performs time-critical tasks that must be executed immediately for it to run correctly.<br/>
        /// The threads of a high-priority class process preempt the threads of normal-priority or idle-priority class processes.<br/>
        /// An example is Windows Task List, which must respond quickly when called by the user, regardless of the load on the operating system.<br/>
        /// Use extreme care when using the high-priority class, because a high-priority class CPU-bound application can use nearly all available cycles.<br/>
        /// Only Realtime priority will preempt threads set to this level<br/>
        /// Idle - Indicates a process whose threads run only when the system is idle and are preempted by the threads of any process running in a higher priority class.<br/>
        /// An example is a screen saver.<br/>
        /// The idle priority class is inherited by child processes.<br/>
        /// Normal - Indicates a normal process with no special scheduling needs.<br/>
        /// Realtime - Indicates a process that has the highest possible priority.<br/>
        /// The threads of a real-time priority class process preempt the threads of all other processes, including operating system processes performing important tasks, and high priority threads.<br/>
        /// For example, a real-time process that executes for more than a very brief interval can cause disk caches not to flush or cause the mouse to be unresponsive.<br/>
        /// Above_Normal - (Windows 2000 and later) Indicates a process that has priority higher than Normal but lower than High.<br/>
        /// Below_Normal - (Windows 2000 and later): Indicates a process that has priority higher than Idle but lower than Normal.<br/>
        /// <br/>
        /// cimtype: uint32<br/>
        /// <br/>
        /// </summary>
        public UInt32 PriorityClass { get; set; }
